const evenements = $input.all().map(i => i.json);
const creneauxProposes = [];
const maintenant = new Date();

for (let j = 1; j <= 14; j++) {
  const date = new Date(maintenant);
  date.setDate(date.getDate() + j);
  if ([0, 6].includes(date.getDay())) continue;

  const creneaux = [
    { heure: 9, duree: 60 },
    { heure: 11, duree: 60 },
    { heure: 14, duree: 60 },
    { heure: 16, duree: 60 }
  ];

  for (const creneau of creneaux) {
    const debut = new Date(date);
    debut.setHours(creneau.heure, 0, 0, 0);
    const fin = new Date(debut);
    fin.setMinutes(fin.getMinutes() + creneau.duree);

    const occupe = evenements.some(e => {
      const eDebut = new Date(e.start?.dateTime || e.start?.date);
      const eFin = new Date(e.end?.dateTime || e.end?.date);
      return debut < eFin && fin > eDebut;
    });

    if (!occupe && creneauxProposes.length < 5) {
      creneauxProposes.push({
        debut: debut.toISOString(),
        fin: fin.toISOString(),
        label: debut.toLocaleString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', hour: '2-digit', minute: '2-digit' })
      });
    }
  }
}

return {
  creneaux: creneauxProposes,
  demandeur: $('Webhook Demande RDV').item.json
};
